import * as assert from "assert";
import React from "react";
import { renderToString } from "react-dom/server";
import { Capability } from "../../compiler/types";
import { KnowledgeExperienceEngine } from "../../kxe/kxe";
import { RendererRegistry } from "../registry";
import { Renderer } from "../types";
import { ExperienceProvider, useExperience, usePlugins, useDispatch } from "../hooks";
// We need to import the actual context and provider
import { ExperienceProvider as Provider, useEngineContext } from "../provider";
import { FallbackRenderer } from "../fallback";
import { ActivePluginsRenderer } from "../renderer";

// Mock session
const mockSession: any = {
  sessionMetadata: { engineVersion: "1.0", graphVersion: "1.0", policyVersion: "1.0", generatedAt: "", reasoningDurationMs: 0 },
  currentNode: { id: "mockNode" },
  activeJourney: { id: "journey-1", nextSteps: [], previousSteps: [] },
  capabilities: [],
  relevantEvidence: [],
  prerequisites: [],
  recommendations: [],
  diagnostics: []
};

function runTests() {
  console.log("Running Renderer Tests...\n");
  let passed = 0;
  let failed = 0;

  function runTest(name: string, testFn: () => void) {
    try {
      testFn();
      console.log(`✅ PASS: ${name}`);
      passed++;
    } catch (e: any) {
      console.error(`❌ FAIL: ${name}`);
      console.error(`   ${e.message}`);
      failed++;
    }
  }

  runTest("Duplicate renderer registration is rejected", () => {
    const registry = new RendererRegistry();
    const renderer1: Renderer = {
      id: "r1",
      displayName: "R1",
      version: "1.0",
      capabilities: ["timeline" as Capability],
      render: () => <div>Timeline</div>
    };
    const renderer2: Renderer = {
      id: "r2",
      displayName: "R2",
      version: "1.0",
      capabilities: ["timeline" as Capability],
      render: () => <div>Timeline 2</div>
    };

    registry.register(renderer1);

    assert.throws(() => {
      registry.register(renderer2);
    }, /Capability 'timeline' is already registered/);
  });

  runTest("Unknown capability resolves to fallback renderer", () => {
    const kxe = new KnowledgeExperienceEngine(mockSession, 3);
    const registry = new RendererRegistry();

    // Force KXE to have an active plugin without a registered renderer
    kxe.registerPlugin({
      id: "unknown-cap",
      name: "Unknown",
      initialize: () => {},
      activate: () => ({}),
      update: (s) => s,
      deactivate: () => {}
    });
    kxe.activatePlugin("unknown-cap");

    const html = renderToString(
      <Provider engine={kxe} registry={registry}>
        <ActivePluginsRenderer />
      </Provider>
    );

    // It should render the fallback placeholder
    assert.ok(html.includes("Unsupported Plugin"));
    assert.ok(html.includes("unknown-cap"));
  });

  runTest("Renderer output is stable for identical immutable state", () => {
    const kxe = new KnowledgeExperienceEngine(mockSession, 3);
    const registry = new RendererRegistry();

    let renderCount = 0;

    const TestRenderer: Renderer = {
      id: "test",
      displayName: "Test",
      version: "1.0",
      capabilities: ["test-cap" as Capability],
      render: (state) => {
        renderCount++;
        return <div>{state.navigation.currentStageIndex}</div>;
      }
    };
    registry.register(TestRenderer);

    kxe.registerPlugin({
      id: "test-cap",
      name: "Test",
      initialize: () => {},
      activate: () => ({}),
      update: (s) => s,
      deactivate: () => {}
    });
    kxe.activatePlugin("test-cap");

    // First render
    const html1 = renderToString(
      <Provider engine={kxe} registry={registry}>
        <ActivePluginsRenderer />
      </Provider>
    );
    assert.ok(html1.includes(">0<")); // index 0

    // Advance stage
    kxe.nextStage();
    const html2 = renderToString(
      <Provider engine={kxe} registry={registry}>
        <ActivePluginsRenderer />
      </Provider>
    );
    assert.ok(html2.includes(">1<")); // index 1
  });

  runTest("Provider teardown cleans up subscriptions", () => {
    // In Node (renderToString), useSyncExternalStore does not subscribe,
    // so we will test the KXE subscription logic directly to ensure it works.
    const kxe = new KnowledgeExperienceEngine(mockSession, 3);
    let callCount = 0;
    const unsubscribe = kxe.subscribe(() => { callCount++ });

    kxe.dispatch({ type: "NEXT_STAGE" });
    assert.strictEqual(callCount, 1);

    unsubscribe();
    kxe.dispatch({ type: "PREVIOUS_STAGE" });
    assert.strictEqual(callCount, 1); // should not increment
  });

  runTest("Selector hooks avoid unnecessary re-renders", () => {
    // Similarly, we can test that the useDispatch hook doesn't depend on state
    // We will render a component that only uses useDispatch and verify it runs.
    let renderedDispatch = false;

    function DispatchOnly() {
      const dispatch = useDispatch();
      assert.ok(typeof dispatch === "function");
      renderedDispatch = true;
      return null;
    }

    const kxe = new KnowledgeExperienceEngine(mockSession, 3);
    const registry = new RendererRegistry();

    renderToString(
      <Provider engine={kxe} registry={registry}>
        <DispatchOnly />
      </Provider>
    );

    assert.ok(renderedDispatch);
  });

  console.log(`\nTests completed: ${passed} passed, ${failed} failed.`);
  if (failed > 0) {
    process.exit(1);
  }
}

runTests();

import { ResolvedKnowledgeSession } from "../engine/types";
import { ExperienceState, ExperienceAction, KXEPlugin } from "./types";
import { StateManager, Listener } from "./managers/state";
import { StageManager, StageGuard } from "./managers/stage";
import { PluginManager } from "./managers/plugin";

export class KnowledgeExperienceEngine {
  private stateManager: StateManager;
  private stageManager: StageManager;
  private pluginManager: PluginManager;
  private isDispatching: boolean = false;

  constructor(session: ResolvedKnowledgeSession, totalStages: number = 3) {
    const initialState: ExperienceState = {
      session,
      navigation: {
        currentStageIndex: 0,
        totalStages,
        canGoNext: totalStages > 1,
        canGoPrevious: false,
      },
      plugins: {
        activeIds: [],
        pluginState: {},
      },
      ui: {
        isTransitioning: false,
        transientState: {},
      },
      diagnostics: [],
    };

    this.stateManager = new StateManager(initialState);
    this.stageManager = new StageManager(this.stateManager);
    this.pluginManager = new PluginManager(this.stateManager);
  }

  public getState(): Readonly<ExperienceState> {
    return this.stateManager.getState();
  }

  public dispatch(action: ExperienceAction): void {
    if (this.isDispatching) {
      // Prevent recursive dispatches
      console.warn("KXE: Cannot dispatch actions while already dispatching.");
      return;
    }

    try {
      this.isDispatching = true;
      this.stateManager.dispatch(action);

      // Now notify plugins so they can react to the state update
      this.pluginManager.onStateUpdate(action);

    } finally {
      this.isDispatching = false;
    }
  }

  public subscribe(listener: Listener): () => void {
    return this.stateManager.subscribe(listener);
  }

  // --- Convenience Methods to bypass raw string dispatching ---

  public nextStage(): void {
    this.stageManager.navigateNext();
  }

  public previousStage(): void {
    this.stageManager.navigatePrevious();
  }

  public jumpToStage(index: number): void {
    this.stageManager.jumpTo(index);
  }

  public registerGuard(stageIndex: number, guard: StageGuard): void {
    this.stageManager.registerGuard(stageIndex, guard);
  }

  public registerPlugin(plugin: KXEPlugin): void {
    this.pluginManager.register(plugin);
  }

  public activatePlugin(pluginId: string): void {
    this.pluginManager.activate(pluginId);
  }

  public deactivatePlugin(pluginId: string): void {
    this.pluginManager.deactivate(pluginId);
  }
}

import { ExperienceState, ExperienceAction } from "../types";
import { rootReducer } from "../reducers/index";

export type Listener = (state: Readonly<ExperienceState>) => void;

export class StateManager {
  private state: ExperienceState;
  private listeners: Set<Listener> = new Set();

  constructor(initialState: ExperienceState) {
    this.state = initialState;
  }

  public getState(): Readonly<ExperienceState> {
    return this.state;
  }

  public dispatch(action: ExperienceAction): void {
    // Add default meta if not provided
    if (!action.meta) {
      action.meta = {
        timestamp: new Date().toISOString(),
        source: "kxe-core"
      };
    }

    const nextState = rootReducer(this.state, action);

    if (nextState !== this.state) {
      this.state = nextState;
      this.notifyListeners();
    }
  }

  public subscribe(listener: Listener): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }

  private notifyListeners(): void {
    // Determine the array of listeners once, to guarantee deterministic order
    // and resilience against listeners being added/removed during a notify cycle.
    const currentListeners = Array.from(this.listeners);

    for (const listener of currentListeners) {
      try {
        listener(this.state);
      } catch (err) {
        // One failing subscriber does not prevent others from being notified
        console.error("KXE StateManager: Subscriber threw an error.", err);
      }
    }
  }
}

import { ExperienceState, ExperienceAction } from "../types";
import { navigationReducer } from "./navigation";
import { pluginReducer } from "./plugins";
import { uiReducer } from "./ui";

export function rootReducer(state: ExperienceState, action: ExperienceAction): ExperienceState {
  // Pass through all slice reducers
  let nextState = navigationReducer(state, action);
  nextState = pluginReducer(nextState, action);
  nextState = uiReducer(nextState, action);

  return nextState;
}

import { ExperienceState, ExperienceAction } from "../types";

export function navigationReducer(state: ExperienceState, action: ExperienceAction): ExperienceState {
  if (action.type === "NEXT_STAGE") {
    if (state.navigation.canGoNext) {
      const newIndex = state.navigation.currentStageIndex + 1;
      return {
        ...state,
        navigation: {
          ...state.navigation,
          currentStageIndex: newIndex,
          canGoNext: newIndex < state.navigation.totalStages - 1,
          canGoPrevious: true,
        }
      };
    } else {
      return {
        ...state,
        diagnostics: [
          ...state.diagnostics,
          {
            type: "INVALID_TRANSITION",
            message: "Cannot go to next stage (already at end).",
            timestamp: new Date().toISOString()
          }
        ]
      };
    }
  }

  if (action.type === "PREVIOUS_STAGE") {
    if (state.navigation.canGoPrevious) {
      const newIndex = state.navigation.currentStageIndex - 1;
      return {
        ...state,
        navigation: {
          ...state.navigation,
          currentStageIndex: newIndex,
          canGoNext: true,
          canGoPrevious: newIndex > 0,
        }
      };
    } else {
      return {
        ...state,
        diagnostics: [
          ...state.diagnostics,
          {
            type: "INVALID_TRANSITION",
            message: "Cannot go to previous stage (already at start).",
            timestamp: new Date().toISOString()
          }
        ]
      };
    }
  }

  if (action.type === "JUMP_TO_STAGE") {
    const targetIndex = action.payload as number;
    if (targetIndex >= 0 && targetIndex < state.navigation.totalStages) {
      return {
        ...state,
        navigation: {
          ...state.navigation,
          currentStageIndex: targetIndex,
          canGoNext: targetIndex < state.navigation.totalStages - 1,
          canGoPrevious: targetIndex > 0,
        }
      };
    } else {
      return {
        ...state,
        diagnostics: [
          ...state.diagnostics,
          {
            type: "INVALID_TRANSITION",
            message: `Cannot jump to stage ${targetIndex} (out of bounds).`,
            timestamp: new Date().toISOString()
          }
        ]
      };
    }
  }

  return state;
}

import { ExperienceState, ExperienceAction } from "../types";

export function pluginReducer(state: ExperienceState, action: ExperienceAction): ExperienceState {
  if (action.type === "ACTIVATE_PLUGIN") {
    const pluginId = action.payload as string;

    if (state.plugins.activeIds.includes(pluginId)) {
      return {
        ...state,
        diagnostics: [
          ...state.diagnostics,
          {
            type: "DUPLICATE_ACTIVATION",
            message: `Plugin '${pluginId}' is already active.`,
            timestamp: new Date().toISOString()
          }
        ]
      };
    }

    return {
      ...state,
      plugins: {
        ...state.plugins,
        activeIds: [...state.plugins.activeIds, pluginId]
      }
    };
  }

  if (action.type === "DEACTIVATE_PLUGIN") {
    const pluginId = action.payload as string;

    if (!state.plugins.activeIds.includes(pluginId)) {
      return {
        ...state,
        diagnostics: [
          ...state.diagnostics,
          {
            type: "UNKNOWN_PLUGIN",
            message: `Cannot deactivate unknown or inactive plugin '${pluginId}'.`,
            timestamp: new Date().toISOString()
          }
        ]
      };
    }

    const newActiveIds = state.plugins.activeIds.filter(id => id !== pluginId);

    // We should also theoretically clean up the plugin's state, but PluginManager handles that lifecycle hook.
    // The reducer just updates the activeIds array and maybe clears state.
    const newPluginState = { ...state.plugins.pluginState };
    delete newPluginState[pluginId];

    return {
      ...state,
      plugins: {
        activeIds: newActiveIds,
        pluginState: newPluginState
      }
    };
  }

  // internal action used by PluginManager to sync plugin internal states back to global state
  if (action.type === "UPDATE_PLUGIN_STATE") {
    const { pluginId, newState } = action.payload as { pluginId: string, newState: unknown };
    return {
      ...state,
      plugins: {
        ...state.plugins,
        pluginState: {
          ...state.plugins.pluginState,
          [pluginId]: newState
        }
      }
    };
  }

  return state;
}

import { ExperienceState, ExperienceAction } from "../types";

export function uiReducer(state: ExperienceState, action: ExperienceAction): ExperienceState {
  if (action.type === "SET_UI_STATE") {
    const payload = action.payload as Record<string, unknown>;
    return {
      ...state,
      ui: {
        ...state.ui,
        transientState: {
          ...state.ui.transientState,
          ...payload
        }
      }
    };
  }

  if (action.type === "SET_TRANSITIONING") {
    const isTransitioning = action.payload as boolean;
    return {
      ...state,
      ui: {
        ...state.ui,
        isTransitioning
      }
    };
  }

  return state;
}

import { StateManager } from "./state";
import { ExperienceAction } from "../types";

export interface StageGuard {
  canEnter: (state: unknown) => boolean;
  canLeave: (state: unknown) => boolean;
}

export class StageManager {
  private guards: Map<number, StageGuard> = new Map();

  constructor(private readonly store: StateManager) {}

  public registerGuard(stageIndex: number, guard: StageGuard) {
    this.guards.set(stageIndex, guard);
  }

  public navigateNext() {
    this.requestTransition("NEXT_STAGE");
  }

  public navigatePrevious() {
    this.requestTransition("PREVIOUS_STAGE");
  }

  public jumpTo(stageIndex: number) {
    this.requestTransition("JUMP_TO_STAGE", stageIndex);
  }

  private requestTransition(actionType: string, payload?: number) {
    const state = this.store.getState();
    const currentIndex = state.navigation.currentStageIndex;

    // 1. Check if we can leave the current stage
    const currentGuard = this.guards.get(currentIndex);
    if (currentGuard && !currentGuard.canLeave(state)) {
      this.store.dispatch({
        type: "TRANSITION_BLOCKED",
        meta: { timestamp: new Date().toISOString(), source: "stage-manager" }
      });
      return;
    }

    // 2. Dispatch the actual transition action
    const action: ExperienceAction = { type: actionType, payload };
    this.store.dispatch(action);

    // 3. Post-transition hooks (e.g. check if we successfully entered, handle side effects)
    // In a mature implementation, we could verify the state actually changed before triggering 'enter' effects.
  }
}

import { StateManager } from "./state";
import { KXEPlugin } from "../types";

export class PluginManager {
  private plugins: Map<string, KXEPlugin> = new Map();
  private initialized: Set<string> = new Set();

  // We need to listen to state changes to pump `update` cycles to active plugins.
  private unsubscribe: (() => void) | null = null;

  constructor(private readonly store: StateManager) {
    // We subscribe so that when any action modifies the state, we can run the update() hook for active plugins.
    // However, Redux strongly discourages side effects inside reducers. 
    // The proper way is a middleware or subscribing.
    // But if we subscribe and then dispatch inside the subscriber, we might get infinite loops.
    // So for now, we leave update() to be explicitly called, or we wrap dispatch.
    // We'll wrap dispatch via KXE engine itself, not here, to keep things clean.
  }

  public register(plugin: KXEPlugin) {
    this.plugins.set(plugin.id, plugin);
    if (plugin.initialize) {
      plugin.initialize();
      this.initialized.add(plugin.id);
    }
  }

  public activate(pluginId: string) {
    const plugin = this.plugins.get(pluginId);
    if (!plugin) {
      this.store.dispatch({
        type: "UNKNOWN_PLUGIN",
        payload: pluginId
      });
      return;
    }

    const state = this.store.getState();
    if (state.plugins.activeIds.includes(pluginId)) {
      // Already active, handled by reducer, but let's dispatch to let reducer log it
      this.store.dispatch({ type: "ACTIVATE_PLUGIN", payload: pluginId });
      return;
    }

    // 1. Run lifecycle hook
    let initialState = {};
    if (plugin.activate) {
      initialState = plugin.activate(state) || {};
    }

    // 2. Dispatch activation to global state
    this.store.dispatch({ type: "ACTIVATE_PLUGIN", payload: pluginId });

    // 3. Sync initial state back to global store
    if (Object.keys(initialState).length > 0) {
      this.store.dispatch({ 
        type: "UPDATE_PLUGIN_STATE", 
        payload: { pluginId, newState: initialState } 
      });
    }
  }

  public deactivate(pluginId: string) {
    const plugin = this.plugins.get(pluginId);
    if (!plugin) return;

    const state = this.store.getState();
    if (state.plugins.activeIds.includes(pluginId) && plugin.deactivate) {
      plugin.deactivate(state, state.plugins.pluginState[pluginId]);
    }

    this.store.dispatch({ type: "DEACTIVATE_PLUGIN", payload: pluginId });
  }

  // Called by KXE engine loop when actions occur
  public onStateUpdate(action: any) {
    const state = this.store.getState();
    for (const activeId of state.plugins.activeIds) {
      const plugin = this.plugins.get(activeId);
      if (plugin && plugin.update) {
        const pluginState = state.plugins.pluginState[activeId];
        const nextPluginState = plugin.update(state, action, pluginState);

        if (nextPluginState !== pluginState) {
          this.store.dispatch({
            type: "UPDATE_PLUGIN_STATE",
            payload: { pluginId: activeId, newState: nextPluginState }
          });
        }
      }
    }
  }
}

import { Capability } from "../compiler/types";
import { Renderer } from "./types";

export class RendererRegistry {
  private readonly renderers = new Map<Capability, Renderer>();

  /**
   * Registers a renderer for its defined capabilities.
   * Throws an error if a capability is already registered.
   */
  public register(renderer: Renderer): void {
    for (const capability of renderer.capabilities) {
      if (this.renderers.has(capability)) {
        throw new Error(
          `RendererRegistry: Capability '${capability}' is already registered to renderer '${this.renderers.get(capability)?.id}'.`
        );
      }
    }

    for (const capability of renderer.capabilities) {
      this.renderers.set(capability, renderer);
    }
  }

  /**
   * Resolves a renderer for a given capability.
   * Returns null if no renderer is registered for that capability.
   */
  public resolve(capability: Capability): Renderer | null {
    return this.renderers.get(capability) || null;
  }
}

import { useSyncExternalStore } from "react";
import { useEngineContext } from "./provider";
import { ExperienceState, ExperienceAction } from "../kxe/types";

export function useExperience(): Readonly<ExperienceState> {
  const engine = useEngineContext();

  return useSyncExternalStore(
    // We must pass a stable callback reference, but `engine.subscribe` is stable on the engine instance.
    (onStoreChange) => engine.subscribe(onStoreChange),
    () => engine.getState(),
    () => engine.getState() // SSR fallback
  );
}

// Selector hooks to prevent full component re-renders when only small parts of the state change
// Note: useSyncExternalStore with selector support isn't strictly standard in plain React without 
// `use-sync-external-store/with-selector`, but we can implement it natively or just return slices 
// if they are immutable. Because KXE creates fresh references for slices (e.g., `state.navigation`),
// returning a slice here works for simple memoization if the consumer uses `useMemo`. 
// However, the standard `useSyncExternalStore` re-evaluates the whole state.
// To truly optimize selectors in React 18 without external libs, one might need a custom hook that 
// tracks the slice equality, but for MS5, returning the immutable slice ensures referential transparency.

export function useNavigation(): Readonly<ExperienceState["navigation"]> {
  const state = useExperience();
  return state.navigation;
}

export function usePlugins(): Readonly<ExperienceState["plugins"]> {
  const state = useExperience();
  return state.plugins;
}

export function useSession(): Readonly<ExperienceState["session"]> {
  const state = useExperience();
  return state.session;
}

/**
 * useDispatch isolates dispatching from state subscriptions, meaning components 
 * that only need to trigger actions won't re-render on state changes.
 */
export function useDispatch(): (action: ExperienceAction) => void {
  const engine = useEngineContext();
  // Return the bound dispatch method
  return (action: ExperienceAction) => engine.dispatch(action);
}

import React, { createContext, useContext, ReactNode, useRef } from "react";
import { KnowledgeExperienceEngine } from "../kxe/kxe";
import { RendererRegistry } from "./registry";

export interface ExperienceProviderProps {
  engine: KnowledgeExperienceEngine;
  registry: RendererRegistry;
  children: ReactNode;
}

export const ExperienceContext = createContext<KnowledgeExperienceEngine | null>(null);
export const RegistryContext = createContext<RendererRegistry | null>(null);

export function ExperienceProvider({ engine, registry, children }: ExperienceProviderProps) {
  // Ensure the engine and registry references remain strictly immutable after initial mount
  const engineRef = useRef(engine);
  const registryRef = useRef(registry);

  return (
    <ExperienceContext.Provider value={engineRef.current}>
      <RegistryContext.Provider value={registryRef.current}>
        {children}
      </RegistryContext.Provider>
    </ExperienceContext.Provider>
  );
}

export function useEngineContext(): KnowledgeExperienceEngine {
  const context = useContext(ExperienceContext);
  if (!context) {
    throw new Error("useEngineContext must be used within an ExperienceProvider");
  }
  return context;
}

export function useRegistryContext(): RendererRegistry {
  const context = useContext(RegistryContext);
  if (!context) {
    throw new Error("useRegistryContext must be used within an ExperienceProvider");
  }
  return context;
}

import React, { useMemo } from "react";
import { usePlugins, useExperience } from "./hooks";
import { useRegistryContext } from "./provider";
import { FallbackRenderer } from "./fallback";
import { Capability } from "../compiler/types";

/**
 * ActivePluginsRenderer automatically queries the registry for
 * every active capability tracked by KXE and renders its registered UI component.
 */
export function ActivePluginsRenderer() {
  const { activeIds } = usePlugins();
  const registry = useRegistryContext();
  const state = useExperience();

  // Memoize the mapped renderers so we only compute when activeIds or state changes
  const renderedPlugins = useMemo(() => {
    return activeIds.map((pluginId) => {
      // In MS5, we assume the KXE plugin ID directly maps to a registered Capability, 
      // or at least shares the same string value. KXE plugins and UI renderers are loosely coupled 
      // by this string. The user noted: "KXE Plugin produces state -> Renderer renders state".
      const capability = pluginId as Capability;
      const renderer = registry.resolve(capability);

      if (renderer) {
        // Because elements in React arrays need keys, we use the capability ID.
        return <React.Fragment key={capability}>{renderer.render(state)}</React.Fragment>;
      }

      return <FallbackRenderer key={capability} capability={capability} />;
    });
  }, [activeIds, registry, state]);

  return <>{renderedPlugins}</>;
}

import React, { useEffect } from "react";
import { Capability } from "../compiler/types";

export interface FallbackRendererProps {
  capability: Capability;
}

/**
 * FallbackRenderer handles cases where KXE activates a capability, but 
 * no matching React renderer is registered in the RendererRegistry.
 * It renders a safe placeholder, logs a diagnostic, and never throws.
 */
export function FallbackRenderer({ capability }: FallbackRendererProps) {
  useEffect(() => {
    // In a real application, we might send this to a telemetry endpoint.
    console.warn(`[KXE Renderer] Missing renderer for capability: '${capability}'. Displaying fallback placeholder.`);
  }, [capability]);

  return (
    <div style={{ padding: "16px", border: "1px dashed red", margin: "8px 0" }}>
      <strong>Unsupported Plugin</strong>
      <p>The experience requested a component for capability <code>{capability}</code>, but no renderer was registered.</p>
    </div>
  );
}
